using UnityEngine;
using UnityEngine.UIElements;
public class Script
{
    public static object Main()
    {
        var docs = Object.FindObjectsOfType<UIDocument>();
        foreach (var doc in docs)
        {
            if (doc.rootVisualElement == null) continue;
            // 尝试关闭公告
            var announcement = doc.rootVisualElement.Q("SplashAnnouncement");
            if (announcement != null)
            {
                var closeBtn = announcement.Q<Button>("btn-close");
                if (closeBtn != null)
                {
                    using (var evt = ClickEvent.GetPooled()) { evt.target = closeBtn; closeBtn.SendEvent(evt); }
                    return "Closed announcement";
                }
            }
            // 尝试点击登录
            var loginBtn = doc.rootVisualElement.Q<Button>("btn-login");
            if (loginBtn != null)
            {
                using (var evt = ClickEvent.GetPooled()) { evt.target = loginBtn; loginBtn.SendEvent(evt); }
                return "Clicked btn-login";
            }
            // 尝试点击继续
            var continueBtn = doc.rootVisualElement.Q<Button>("btn-continue");
            if (continueBtn != null)
            {
                using (var evt = ClickEvent.GetPooled()) { evt.target = continueBtn; continueBtn.SendEvent(evt); }
                return "Clicked btn-continue";
            }
        }
        return "No login UI found (may already be in game)";
    }
}
